Here's a complete implementation:

### XAML — `ItemsPage.xaml`

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             xmlns:models="clr-namespace:MyApp.Models"
             xmlns:viewmodels="clr-namespace:MyApp.ViewModels"
             x:Class="MyApp.Views.ItemsPage"
             x:DataType="viewmodels:ItemsViewModel">

    <RefreshView IsRefreshing="{Binding IsRefreshing}"
                 Command="{Binding RefreshCommand}">

        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                        SelectionChangedCommand="{Binding ItemSelectedCommand}">

            <CollectionView.ItemsLayout>
                <LinearItemsLayout Orientation="Vertical"
                                   ItemSizingStrategy="MeasureFirstItem" />
            </CollectionView.ItemsLayout>

            <CollectionView.ItemTemplate>
                <DataTemplate x:DataType="models:Item">
                    <Grid Padding="12" ColumnDefinitions="48,*" ColumnSpacing="12">
                        <Image Source="{Binding Icon}"
                               WidthRequest="40" HeightRequest="40" />
                        <VerticalStackLayout Grid.Column="1" VerticalOptions="Center">
                            <Label Text="{Binding Name}" FontAttributes="Bold" />
                            <Label Text="{Binding Description}"
                                   FontSize="12" TextColor="Gray" />
                        </VerticalStackLayout>
                    </Grid>
                </DataTemplate>
            </CollectionView.ItemTemplate>

            <CollectionView.EmptyView>
                <ContentView>
                    <Label Text="No items found."
                           HorizontalOptions="Center" VerticalOptions="Center" />
                </ContentView>
            </CollectionView.EmptyView>

        </CollectionView>
    </RefreshView>
</ContentPage>
```

### ViewModel — `ItemsViewModel.cs`

```csharp
using CommunityToolkit.Mvvm.ComponentModel;
using CommunityToolkit.Mvvm.Input;
using System.Collections.ObjectModel;

public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;

    public ItemsViewModel(IApiService api)
    {
        _api = api;
    }

    public ObservableCollection<Item> Items { get; } = new();

    [ObservableProperty]
    private Item? currentItem;

    [ObservableProperty]
    private bool isRefreshing;

    [RelayCommand]
    private async Task ItemSelectedAsync()
    {
        if (CurrentItem is null) return;

        await Shell.Current.GoToAsync(
            $"{nameof(DetailPage)}",
            new Dictionary<string, object> { ["Item"] = CurrentItem });

        // Clear selection so user can re-select the same item later
        CurrentItem = null;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items.Clear();
            foreach (var item in data)
                Items.Add(item);
        }
        finally
        {
            IsRefreshing = false; // Must set false to hide spinner
        }
    }
}
```

### Key binding relationships

| XAML Property | ViewModel Property | Why |
|---|---|---|
| `RefreshView.IsRefreshing` | `IsRefreshing` (bool) | Two-way — shows/hides spinner; **set `false` when done** |
| `RefreshView.Command` | `RefreshCommand` | Fires on pull-down gesture |
| `CollectionView.ItemsSource` | `Items` (`ObservableCollection<T>`) | Auto-updates UI on add/remove |
| `CollectionView.SelectedItem` | `CurrentItem` (TwoWay) | Tracks which item is tapped |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Triggers navigation via `GoToAsync` |

### Important notes

- **Use `ObservableCollection<T>`**, not `List<T>` — otherwise the UI won't update.
- **Set `IsRefreshing = false`** in a `finally` block so the spinner always hides.
- **Clear `CurrentItem`** after navigation so the same item can be re-selected.
- **`MeasureFirstItem`** improves scroll performance when items are uniform height.
- **Never use `ViewCell`** — use `Grid`, `StackLayout`, or any `View` as the template root.
